import json

schema = json.load(open('.forge/schemas/project-context.schema.json'))
data = json.load(open('.forge/project-context.json'))

# Check required fields
errors = []

# project is required
if 'project' not in data:
    errors.append('project is missing')
else:
    p = data['project']
    if not p.get('name'):
        errors.append('project.name is missing or empty')
    if not p.get('prefix'):
        errors.append('project.prefix is missing or empty')

# Check array fields are arrays
for key in ['entities', 'impactCategories', 'technicalDebt', 'skillWiring']:
    if key in data and not isinstance(data[key], list):
        errors.append(f'{key} must be an array')

# Check architecture.keyDirectories is array
if 'architecture' in data and 'keyDirectories' in data['architecture']:
    if not isinstance(data['architecture']['keyDirectories'], list):
        errors.append('architecture.keyDirectories must be an array')

# Check deployment.environments is array
if 'deployment' in data and 'environments' in data['deployment']:
    if not isinstance(data['deployment']['environments'], list):
        errors.append('deployment.environments must be an array')

if errors:
    for e in errors:
        print(f'ERROR: {e}')
    exit(1)
else:
    print('project-context.json is structurally valid')
    print(f'  project.name: {data[\"project\"][\"name\"]}')
    print(f'  project.prefix: {data[\"project\"][\"prefix\"]}')
    print(f'  entities: {len(data.get(\"entities\", []))} items')
    print(f'  stack: {data[\"project\"].get(\"stack\", [])}')
"
